import React, { useState } from "react";
import { Link } from "react-router-dom"; // Make sure to install react-router-dom if not already done
import "../styles/News.css";

const newsArticles = [
  {
    id: 1,
    title: "Legal Insights: 2025 Changes",
    img: "/images/news1.jpg",
    description: "A brief overview of the most important changes in the legal landscape for 2025...",
    fullText: "Detailed article about the legal changes happening in 2025, including impact on businesses and individual rights...",
  },
  {
    id: 2,
    title: "New Privacy Laws: What You Need to Know",
    img: "/images/news2.jpg",
    description: "Understanding the new privacy laws and how they affect data protection and online security...",
    fullText: "Full article discussing the changes to privacy laws and their implications on data security and consumer rights...",
  },
  {
    id: 3,
    title: "Corporate Mergers: A Rising Trend",
    img: "/images/news3.jpg",
    description: "The trend of mergers and acquisitions in the corporate world is growing. What this means for the future of business...",
    fullText: "Full article analyzing the increase in corporate mergers, reasons behind the trend, and future forecasts...",
  },
];

const News = () => {
  const [showAll, setShowAll] = useState(false);

  return (
    <div className="news-section">
      <h2 className="news-title">News & Articles</h2>
      <p className="news-subtitle">Stay updated with the latest legal news and insights.</p>

      <div className="news-list">
        {newsArticles.slice(0, 3).map((article) => (
          <div key={article.id} className="news-card">
            <img src={article.img} alt={article.title} className="news-img" />
            <h3 className="news-card-title">{article.title}</h3>
            <p className="news-card-description">{article.description}</p>
            <Link to={`/news/${article.id}`} className="read-more-link">
              Read More
            </Link>
          </div>
        ))}
      </div>

      <button className="show-more-btn" onClick={() => setShowAll(true)}>
        Show More
      </button>

      {showAll && (
        <div className="all-news">
          <h2>All News Articles</h2>
          {newsArticles.map((article) => (
            <div key={article.id} className="news-card">
              <img src={article.img} alt={article.title} className="news-img" />
              <h3 className="news-card-title">{article.title}</h3>
              <p className="news-card-description">{article.description}</p>
              <Link to={`/news/${article.id}`} className="read-more-link">
                Read More
              </Link>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default News;
